import React, { useEffect } from "react";
import { Table, Card, Typography, Avatar, Skeleton, Button, Divider } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { getaOrder, updateAOrder } from "../features/auth/authSlice";
import {
  User,
  ShoppingCart,
  MapPin,
  DollarSign,
  ArrowLeft,
  Package,
  Activity,
  Calendar,
  ShieldCheck,
  CheckCircle2,
  Clock,
  TrendingUp,
  Mail,
  Phone,
  CreditCard,
  FileText,
  XCircle,
  Zap,
  ChevronRight
} from "lucide-react";

const { Text } = Typography;

const ViewOrder = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const orderId = location.pathname.split("/")[3];
  const dispatch = useDispatch();

  useEffect(() => {
    if (orderId) {
      dispatch(getaOrder(orderId));
    }
  }, [dispatch, orderId]);

  const { singleOrder, isLoading } = useSelector((state) => state.auth);
  const orderState = singleOrder?.orders;

  if (isLoading || !orderState) {
    return (
      <div className="p-12 space-y-8 animate-pulse">
        <div className="h-32 bg-slate-100 rounded-[40px]" />
        <div className="grid grid-cols-3 gap-8">
           <div className="col-span-2 h-96 bg-slate-50 rounded-[40px]" />
           <div className="h-96 bg-slate-50 rounded-[40px]" />
        </div>
      </div>
    );
  }

  const tableData = orderState.cart.map((item, index) => ({
    key: index,
    product: {
      name: item.product?.title,
      brand: item.product?.brand,
      image: (Array.isArray(item.product?.colors?.[0]?.images) ? item.product?.colors?.[0]?.images?.[0]?.secure_url : item.product?.colors?.[0]?.images?.secure_url),
    },
    price: item.price,
    count: item.quantity,
    color: item.color?.title,
    total: item.price * item.quantity,
  }));

  const columns = [
    {
      title: "Payload Entity",
      dataIndex: "product",
      key: "product",
      render: (product) => (
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 rounded-[20px] bg-white border border-slate-100 flex items-center justify-center overflow-hidden shadow-sm p-1">
            <img
              src={product.image || "https://api.dicebear.com/7.x/shapes/svg?seed=asset"}
              alt={product.name}
              className="w-full h-full object-cover rounded-[14px]"
            />
          </div>
          <div className="flex flex-col">
            <Text className="font-black text-slate-900 text-[16px] leading-tight tracking-tight">
              {product.name}
            </Text>
            <span className="text-[11px] text-blue-600 font-black mt-2 uppercase tracking-[0.2em] bg-blue-50 w-fit px-3 py-1 rounded-full">
              {product.brand}
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "Unit Value",
      dataIndex: "price",
      key: "price",
      render: (price) => (
        <div className="flex flex-col">
          <span className="font-black text-slate-900 text-[16px]">
            {price.toLocaleString()}
          </span>
          <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
            ETB PER UNIT
          </span>
        </div>
      ),
    },
    {
      title: "Volume",
      dataIndex: "count",
      key: "count",
      render: (count) => (
        <div className="flex flex-col">
          <span className="text-slate-900 font-black text-[16px]">{count}</span>
          <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">
            QUANTITY
          </span>
        </div>
      ),
    },
    {
      title: "Variant",
      dataIndex: "color",
      key: "color",
      render: (color) => (
        <span className="px-4 py-1.5 rounded-xl bg-slate-100 text-slate-600 text-[11px] font-black uppercase tracking-widest">
          {color || "Standard"}
        </span>
      ),
    },
    {
      title: "Total Yield",
      dataIndex: "total",
      key: "total",
      render: (total) => (
        <div className="flex flex-col">
          <span className="font-black text-slate-900 text-[18px] tracking-tighter">
            {total.toLocaleString()}
          </span>
          <span className="text-[10px] text-emerald-500 font-black uppercase tracking-widest">
            ETB TOTAL
          </span>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-12 pb-24 animate-in fade-in zoom-in-95 duration-700">
      {/* Dynamic Header Sector */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
        <div className="space-y-3">
          <div className="flex items-center gap-3">
             <div className="w-1.5 h-1.5 rounded-full bg-blue-600 animate-pulse" />
             <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.3em]">Inspection Mode</span>
          </div>
          <div className="flex items-center gap-6">
             <h1 className="text-[48px] font-black text-slate-900 tracking-tighter leading-none">
               Order <span className="text-blue-600">Protocol</span>
             </h1>
             <div className={`px-6 py-2 rounded-[20px] border border-slate-100 bg-white shadow-xl shadow-slate-200/40 text-[12px] font-black flex items-center gap-3 uppercase tracking-widest text-slate-600`}>
                <div className="w-2 h-2 rounded-full bg-blue-500 animate-ping" />
                {orderState.orderStatus}
             </div>
          </div>
          <p className="text-[15px] font-bold text-slate-400 uppercase tracking-widest">
            Registry Hash: <span className="text-slate-900 font-black ml-2">#{orderState._id.toUpperCase()}</span>
          </p>
        </div>
        
        <Button
          onClick={() => navigate(-1)}
          icon={<ArrowLeft size={20} />}
          className="h-16 px-10 rounded-[24px] font-black uppercase text-[12px] tracking-widest border-slate-200 text-slate-400 hover:text-slate-950 transition-all flex items-center gap-3 group"
        >
          <span className="group-hover:-translate-x-1 transition-transform">Terminal Back</span>
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-10">
          {/* Main Inventory Ledger */}
          <div className="enterprise-card overflow-hidden">
            <div className="px-10 py-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-2xl bg-slate-900 text-white flex items-center justify-center shadow-lg">
                  <Package size={24} />
                </div>
                <div>
                  <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tighter">Inventory Ledger</h3>
                  <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">{tableData.length} Unique Nodes Detected</p>
                </div>
              </div>
            </div>
            <Table
              columns={columns}
              dataSource={tableData}
              pagination={false}
              className="super-modern-table"
            />
          </div>

          {/* Value Architecture */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="enterprise-card p-10 space-y-4">
                 <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Gross Valuation</p>
                 <h2 className="text-[28px] font-black text-slate-900 tracking-tighter italic">ETB {orderState.totalPrice.toLocaleString()}</h2>
                 <div className="w-full h-1 bg-slate-50 rounded-full" />
              </div>
              <div className="enterprise-card p-10 space-y-4">
                 <p className="text-[11px] font-black text-rose-400 uppercase tracking-widest">Discount Deficit</p>
                 <h2 className="text-[28px] font-black text-rose-600 tracking-tighter italic">
                   -{(orderState.totalPrice - (orderState.totalPriceAfterDiscount || orderState.totalPrice)).toLocaleString()}
                 </h2>
                 <div className="w-full h-1 bg-rose-50 rounded-full" />
              </div>
              <div className="bg-slate-950 rounded-[40px] p-10 text-white space-y-4 shadow-2xl shadow-slate-900/20 relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:rotate-12 transition-transform duration-700">
                    <Zap size={100} fill="white" />
                 </div>
                 <p className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Final Deployment Value</p>
                 <h2 className="text-[32px] font-black tracking-tighter italic">
                   ETB {(orderState.totalPriceAfterDiscount || orderState.totalPrice).toLocaleString()}
                 </h2>
                 <button className="text-[11px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2 hover:underline p-0 mt-4">
                    Audit Payment Hash <ChevronRight size={14} />
                 </button>
              </div>
          </div>
        </div>

        <div className="space-y-10">
          {/* Identity Matrix */}
          <div className="enterprise-card p-10 space-y-8">
            <div className="flex items-center gap-4">
               <div className="w-14 h-14 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center">
                  <User size={28} />
               </div>
               <h3 className="text-[18px] font-black text-slate-900 uppercase tracking-tighter">Identity Matrix</h3>
            </div>
            
            <div className="flex items-center gap-6 p-6 rounded-[32px] bg-slate-50 border border-slate-100">
               <Avatar
                 size={72}
                 src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${orderState.email}&backgroundColor=f8fafc`}
                 className="rounded-[24px] border-4 border-white shadow-xl"
               />
               <div className="min-w-0">
                 <h4 className="font-black text-slate-900 text-[20px] leading-tight truncate">{`${orderState.first_name} ${orderState.last_name}`}</h4>
                 <div className="flex items-center gap-2 mt-2 text-slate-400 font-black text-[11px] uppercase tracking-widest truncate">
                   <Mail size={12} /> {orderState.email}
                 </div>
               </div>
            </div>

            <div className="space-y-4 pt-4">
               <div className="flex justify-between items-center px-2">
                  <span className="text-[12px] font-black text-slate-400 uppercase tracking-widest">Temporal Node</span>
                  <span className="text-[14px] font-black text-slate-900">{new Date(orderState.createdAt).toLocaleDateString()}</span>
               </div>
               <div className="flex justify-between items-center px-2">
                  <span className="text-[12px] font-black text-slate-400 uppercase tracking-widest">Direct Contact</span>
                  <span className="text-[14px] font-black text-blue-600">{orderState.phone_number}</span>
               </div>
            </div>
          </div>

          {/* Logistics Node */}
          <div className="enterprise-card p-10 space-y-8">
            <div className="flex items-center gap-4">
               <div className="w-14 h-14 rounded-2xl bg-indigo-50 text-indigo-600 flex items-center justify-center">
                  <MapPin size={28} />
               </div>
               <h3 className="text-[18px] font-black text-slate-900 uppercase tracking-tighter">Logistics Node</h3>
            </div>

            <div className="p-8 rounded-[36px] bg-slate-900 text-white space-y-4 relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:scale-110 transition-transform duration-700">
                  <TrendingUp size={80} />
               </div>
               <p className="text-[16px] font-black leading-relaxed tracking-tight relative z-10">
                 {orderState.address}
               </p>
               <div className="text-[12px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3 relative z-10">
                 {orderState.city} <span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> ETHIOPIA
               </div>
            </div>

            <div className="flex items-center gap-3 text-emerald-500 bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50">
               <ShieldCheck size={20} />
               <span className="text-[11px] font-black uppercase tracking-widest">Global Delivery Protocol Verified</span>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .super-modern-table .ant-table-thead > tr > th {
          background: #fbfcfd !important;
          font-weight: 800 !important;
          font-size: 11px !important;
          color: #94a3b8 !important;
          text-transform: uppercase !important;
          letter-spacing: 0.15em !important;
          border: none !important;
          padding: 24px 40px !important;
        }
        .super-modern-table .ant-table-tbody > tr > td {
          padding: 24px 40px !important;
          border-bottom: 1px solid #f8fafc !important;
        }
      `}</style>
    </div>
  );
};

export default ViewOrder;
